44: /**
45:  * RecordBatch implementation for magic 2 and above. The schema is given below:
46:  *
47:  * RecordBatch =>
48:  *  BaseOffset => Int64
49:  *  Length => Int32
50:  *  PartitionLeaderEpoch => Int32
51:  *  Magic => Int8
52:  *  CRC => Uint32
53:  *  Attributes => Int16
54:  *  LastOffsetDelta => Int32 // also serves as LastSequenceDelta
55:  *  FirstTimestamp => Int64
56:  *  MaxTimestamp => Int64
57:  *  ProducerId => Int64
58:  *  ProducerEpoch => Int16
59:  *  BaseSequence => Int32
60:  *  Records => [Record]
61:  *
62:  * Note that when compression is enabled (see attributes below), the compressed record data is serialized
63:  * directly following the count of the number of records.
64:  *
65:  * The CRC covers the data from the attributes to the end of the batch (i.e. all the bytes that follow the CRC). It is
66:  * located after the magic byte, which means that clients must parse the magic byte before deciding how to interpret
67:  * the bytes between the batch length and the magic byte. The partition leader epoch field is not included in the CRC
68:  * computation to avoid the need to recompute the CRC when this field is assigned for every batch that is received by
69:  * the broker. The CRC-32C (Castagnoli) polynomial is used for the computation.
70:  *
71:  * On Compaction: Unlike the older message formats, magic v2 and above preserves the first and last offset/sequence
72:  * numbers from the original batch when the log is cleaned. This is required in order to be able to restore the
73:  * producer's state when the log is reloaded. If we did not retain the last sequence number, then following
74:  * a partition leader failure, once the new leader has rebuilt the producer state from the log, the next sequence
75:  * expected number would no longer be in sync with what was written by the client. This would cause an
76:  * unexpected OutOfOrderSequence error, which is typically fatal. The base sequence number must be preserved for
77:  * duplicate checking: the broker checks incoming Produce requests for duplicates by verifying that the first and
78:  * last sequence numbers of the incoming batch match the last from that producer.
79:  *
80:  * Note that if all of the records in a batch are removed during compaction, the broker may still retain an empty
81:  * batch header in order to preserve the producer sequence information as described above. These empty batches
82:  * are retained only until either a new sequence number is written by the corresponding producer or the producerId
83:  * is expired from lack of activity.
84:  *
85:  * There is no similar need to preserve the timestamp from the original batch after compaction. The FirstTimestamp
86:  * field therefore always reflects the timestamp of the first record in the batch. If the batch is empty, the
87:  * FirstTimestamp will be set to -1 (NO_TIMESTAMP).
88:  *
89:  * Similarly, the MaxTimestamp field reflects the maximum timestamp of the current records if the timestamp type
90:  * is CREATE_TIME. For LOG_APPEND_TIME, on the other hand, the MaxTimestamp field reflects the timestamp set
91:  * by the broker and is preserved after compaction. Additionally, the MaxTimestamp of an empty batch always retains
92:  * the previous value prior to becoming empty.
93:  *
94:  * The delete horizon flag for the sixth bit is used to determine if the first timestamp of the batch had been set to
95:  * the time for which tombstones / transaction markers need to be removed. If it is true, then the first timestamp is
96:  * the delete horizon, otherwise, it is merely the first timestamp of the record batch.
97:  *
98:  * The current attributes are given below:
99:  *
100:  *  ---------------------------------------------------------------------------------------------------------------------------
101:  *  | Unused (7-15) | Delete Horizon Flag (6) | Control (5) | Transactional (4) | Timestamp Type (3) | Compression Type (0-2) |
102:  *  ---------------------------------------------------------------------------------------------------------------------------
103:  */
104: public class DefaultRecordBatch extends AbstractRecordBatch implements MutableRecordBatch {
105:     static final int BASE_OFFSET_OFFSET = 0;
106:     static final int BASE_OFFSET_LENGTH = 8;
107:     static final int LENGTH_OFFSET = BASE_OFFSET_OFFSET + BASE_OFFSET_LENGTH;
108:     static final int LENGTH_LENGTH = 4;
109:     static final int PARTITION_LEADER_EPOCH_OFFSET = LENGTH_OFFSET + LENGTH_LENGTH;
110:     static final int PARTITION_LEADER_EPOCH_LENGTH = 4;
111:     static final int MAGIC_OFFSET = PARTITION_LEADER_EPOCH_OFFSET + PARTITION_LEADER_EPOCH_LENGTH;
112:     static final int MAGIC_LENGTH = 1;
113:     static final int CRC_OFFSET = MAGIC_OFFSET + MAGIC_LENGTH;
114:     static final int CRC_LENGTH = 4;
115:     static final int ATTRIBUTES_OFFSET = CRC_OFFSET + CRC_LENGTH;
116:     static final int ATTRIBUTE_LENGTH = 2;
117:     public static final int LAST_OFFSET_DELTA_OFFSET = ATTRIBUTES_OFFSET + ATTRIBUTE_LENGTH;
118:     static final int LAST_OFFSET_DELTA_LENGTH = 4;
119:     static final int BASE_TIMESTAMP_OFFSET = LAST_OFFSET_DELTA_OFFSET + LAST_OFFSET_DELTA_LENGTH;
120:     static final int BASE_TIMESTAMP_LENGTH = 8;
121:     static final int MAX_TIMESTAMP_OFFSET = BASE_TIMESTAMP_OFFSET + BASE_TIMESTAMP_LENGTH;
122:     static final int MAX_TIMESTAMP_LENGTH = 8;
123:     static final int PRODUCER_ID_OFFSET = MAX_TIMESTAMP_OFFSET + MAX_TIMESTAMP_LENGTH;
124:     static final int PRODUCER_ID_LENGTH = 8;
125:     static final int PRODUCER_EPOCH_OFFSET = PRODUCER_ID_OFFSET + PRODUCER_ID_LENGTH;
126:     static final int PRODUCER_EPOCH_LENGTH = 2;
127:     static final int BASE_SEQUENCE_OFFSET = PRODUCER_EPOCH_OFFSET + PRODUCER_EPOCH_LENGTH;
128:     static final int BASE_SEQUENCE_LENGTH = 4;
129:     public static final int RECORDS_COUNT_OFFSET = BASE_SEQUENCE_OFFSET + BASE_SEQUENCE_LENGTH;
130:     static final int RECORDS_COUNT_LENGTH = 4;
131:     static final int RECORDS_OFFSET = RECORDS_COUNT_OFFSET + RECORDS_COUNT_LENGTH;
132:     public static final int RECORD_BATCH_OVERHEAD = RECORDS_OFFSET;
133: 
134:     private static final byte COMPRESSION_CODEC_MASK = 0x07;
135:     private static final byte TRANSACTIONAL_FLAG_MASK = 0x10;
136:     private static final int CONTROL_FLAG_MASK = 0x20;
137:     private static final byte DELETE_HORIZON_FLAG_MASK = 0x40;
138:     private static final byte TIMESTAMP_TYPE_MASK = 0x08;
139: 
140:     private static final int MAX_SKIP_BUFFER_SIZE = 2048;
141: 
142:     private final ByteBuffer buffer;
143: 
144:     DefaultRecordBatch(ByteBuffer buffer) {
145:         this.buffer = buffer;
146:     }
147: 
148:     @Override
149:     public byte magic() {
150:         return buffer.get(MAGIC_OFFSET);
151:     }
152: 
153:     @Override
154:     public void ensureValid() {
155:         if (sizeInBytes() < RECORD_BATCH_OVERHEAD)
156:             throw new CorruptRecordException("Record batch is corrupt (the size " + sizeInBytes() +
157:                     " is smaller than the minimum allowed overhead " + RECORD_BATCH_OVERHEAD + ")");
158: 
159:         if (!isValid())
160:             throw new CorruptRecordException("Record is corrupt (stored crc = " + checksum()
161:                     + ", computed crc = " + computeChecksum() + ")");
162:     }
163: 
164:     /**
165:      * Gets the base timestamp of the batch which is used to calculate the record timestamps from the deltas.
166:      * 
167:      * @return The base timestamp
168:      */
169:     public long baseTimestamp() {
170:         return buffer.getLong(BASE_TIMESTAMP_OFFSET);
171:     }
172: 
173:     @Override
174:     public long maxTimestamp() {
175:         return buffer.getLong(MAX_TIMESTAMP_OFFSET);
176:     }
177: 
178:     @Override
179:     public TimestampType timestampType() {
180:         return (attributes() & TIMESTAMP_TYPE_MASK) == 0 ? TimestampType.CREATE_TIME : TimestampType.LOG_APPEND_TIME;
181:     }
182: 
183:     @Override
184:     public long baseOffset() {
185:         return buffer.getLong(BASE_OFFSET_OFFSET);
186:     }
187: 
188:     @Override
189:     public long lastOffset() {
190:         return baseOffset() + lastOffsetDelta();
191:     }
192: 
193:     @Override
194:     public long producerId() {
195:         return buffer.getLong(PRODUCER_ID_OFFSET);
196:     }
197: 
198:     @Override
199:     public short producerEpoch() {
200:         return buffer.getShort(PRODUCER_EPOCH_OFFSET);
201:     }
202: 
203:     @Override
204:     public int baseSequence() {
205:         return buffer.getInt(BASE_SEQUENCE_OFFSET);
206:     }
207: 
208:     private int lastOffsetDelta() {
209:         return buffer.getInt(LAST_OFFSET_DELTA_OFFSET);
210:     }
211: 
212:     @Override
213:     public int lastSequence() {
214:         int baseSequence = baseSequence();
215:         if (baseSequence == RecordBatch.NO_SEQUENCE)
216:             return RecordBatch.NO_SEQUENCE;
217:         return incrementSequence(baseSequence, lastOffsetDelta());
218:     }
219: 
220:     @Override
221:     public CompressionType compressionType() {
222:         return CompressionType.forId(attributes() & COMPRESSION_CODEC_MASK);
223:     }
224: 
225:     @Override
226:     public int sizeInBytes() {
227:         return LOG_OVERHEAD + buffer.getInt(LENGTH_OFFSET);
228:     }
229: 
230:     private int count() {
231:         return buffer.getInt(RECORDS_COUNT_OFFSET);
232:     }
233: 
234:     @Override
235:     public Integer countOrNull() {
236:         return count();
237:     }
238: 
239:     @Override
240:     public void writeTo(ByteBuffer buffer) {
241:         buffer.put(this.buffer.duplicate());
242:     }
243: 
244:     @Override
245:     public void writeTo(ByteBufferOutputStream outputStream) {
246:         outputStream.write(this.buffer.duplicate());
247:     }
248: 
249:     @Override
250:     public boolean isTransactional() {
251:         return (attributes() & TRANSACTIONAL_FLAG_MASK) > 0;
252:     }
253: 
254:     private boolean hasDeleteHorizonMs() {
255:         return (attributes() & DELETE_HORIZON_FLAG_MASK) > 0;
256:     }
257: 
258:     @Override
259:     public OptionalLong deleteHorizonMs() {
260:         if (hasDeleteHorizonMs())
261:             return OptionalLong.of(buffer.getLong(BASE_TIMESTAMP_OFFSET));
262:         else
263:             return OptionalLong.empty();
264:     }
265: 
266:     @Override
267:     public boolean isControlBatch() {
268:         return (attributes() & CONTROL_FLAG_MASK) > 0;
269:     }
270: 
271:     @Override
272:     public int partitionLeaderEpoch() {
273:         return buffer.getInt(PARTITION_LEADER_EPOCH_OFFSET);
274:     }
275: 
276:     public DataInputStream recordInputStream(BufferSupplier bufferSupplier) {
277:         final ByteBuffer buffer = this.buffer.duplicate();
278:         buffer.position(RECORDS_OFFSET);
279:         return new DataInputStream(compressionType().wrapForInput(buffer, magic(), bufferSupplier));
280:     }
281: 
282:     private CloseableIterator<Record> compressedIterator(BufferSupplier bufferSupplier, boolean skipKeyValue) {
283:         final DataInputStream inputStream = recordInputStream(bufferSupplier);
284: 
285:         if (skipKeyValue) {
286:             // this buffer is used to skip length delimited fields like key, value, headers
287:             byte[] skipArray = new byte[MAX_SKIP_BUFFER_SIZE];
288: 
289:             return new StreamRecordIterator(inputStream) {
290:                 @Override
291:                 protected Record doReadRecord(long baseOffset, long firstTimestamp, int baseSequence, Long logAppendTime) throws IOException {
292:                     return DefaultRecord.readPartiallyFrom(inputStream, skipArray, baseOffset, firstTimestamp, baseSequence, logAppendTime);
293:                 }
294:             };
295:         } else {
296:             return new StreamRecordIterator(inputStream) {
297:                 @Override
298:                 protected Record doReadRecord(long baseOffset, long firstTimestamp, int baseSequence, Long logAppendTime) throws IOException {
299:                     return DefaultRecord.readFrom(inputStream, baseOffset, firstTimestamp, baseSequence, logAppendTime);
300:                 }
301:             };
302:         }
303:     }
304: 
305:     private CloseableIterator<Record> uncompressedIterator() {
306:         final ByteBuffer buffer = this.buffer.duplicate();
307:         buffer.position(RECORDS_OFFSET);
308:         return new RecordIterator() {
309:             @Override
310:             protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
311:                 try {
312:                     return DefaultRecord.readFrom(buffer, baseOffset, baseTimestamp, baseSequence, logAppendTime);
313:                 } catch (BufferUnderflowException e) {
314:                     throw new InvalidRecordException("Incorrect declared batch size, premature EOF reached");
315:                 }
316:             }
317:             @Override
318:             protected boolean ensureNoneRemaining() {
319:                 return !buffer.hasRemaining();
320:             }
321:             @Override
322:             public void close() {}
323:         };
324:     }
325: 
326:     @Override
327:     public Iterator<Record> iterator() {
328:         if (count() == 0)
329:             return Collections.emptyIterator();
330: 
331:         if (!isCompressed())
332:             return uncompressedIterator();
333: 
334:         // for a normal iterator, we cannot ensure that the underlying compression stream is closed,
335:         // so we decompress the full record set here. Use cases which call for a lower memory footprint
336:         // can use `streamingIterator` at the cost of additional complexity
337:         try (CloseableIterator<Record> iterator = compressedIterator(BufferSupplier.NO_CACHING, false)) {
338:             List<Record> records = new ArrayList<>(count());
339:             while (iterator.hasNext())
340:                 records.add(iterator.next());
341:             return records.iterator();
342:         }
343:     }
344: 
345:     @Override
346:     public CloseableIterator<Record> skipKeyValueIterator(BufferSupplier bufferSupplier) {
347:         if (count() == 0) {
348:             return CloseableIterator.wrap(Collections.emptyIterator());
349:         }
350: 
351:         /*
352:          * For uncompressed iterator, it is actually not worth skipping key / value / headers at all since
353:          * its ByteBufferInputStream's skip() function is less efficient compared with just reading it actually
354:          * as it will allocate new byte array.
355:          */
356:         if (!isCompressed())
357:             return uncompressedIterator();
358: 
359:         // we define this to be a closable iterator so that caller (i.e. the log validator) needs to close it
360:         // while we can save memory footprint of not decompressing the full record set ahead of time
361:         return compressedIterator(bufferSupplier, true);
362:     }
363: 
364:     @Override
365:     public CloseableIterator<Record> streamingIterator(BufferSupplier bufferSupplier) {
366:         if (isCompressed())
367:             return compressedIterator(bufferSupplier, false);
368:         else
369:             return uncompressedIterator();
370:     }
371: 
372:     @Override
373:     public void setLastOffset(long offset) {
374:         buffer.putLong(BASE_OFFSET_OFFSET, offset - lastOffsetDelta());
375:     }
376: 
377:     @Override
378:     public void setMaxTimestamp(TimestampType timestampType, long maxTimestamp) {
379:         long currentMaxTimestamp = maxTimestamp();
380:         // We don't need to recompute crc if the timestamp is not updated.
381:         if (timestampType() == timestampType && currentMaxTimestamp == maxTimestamp)
382:             return;
383: 
384:         byte attributes = computeAttributes(compressionType(), timestampType, isTransactional(), isControlBatch(), hasDeleteHorizonMs());
385:         buffer.putShort(ATTRIBUTES_OFFSET, attributes);
386:         buffer.putLong(MAX_TIMESTAMP_OFFSET, maxTimestamp);
387:         long crc = computeChecksum();
388:         ByteUtils.writeUnsignedInt(buffer, CRC_OFFSET, crc);
389:     }
390: 
391:     @Override
392:     public void setPartitionLeaderEpoch(int epoch) {
393:         buffer.putInt(PARTITION_LEADER_EPOCH_OFFSET, epoch);
394:     }
395: 
396:     @Override
397:     public long checksum() {
398:         return ByteUtils.readUnsignedInt(buffer, CRC_OFFSET);
399:     }
400: 
401:     public boolean isValid() {
402:         return sizeInBytes() >= RECORD_BATCH_OVERHEAD && checksum() == computeChecksum();
403:     }
404: 
405:     private long computeChecksum() {
406:         return Crc32C.compute(buffer, ATTRIBUTES_OFFSET, buffer.limit() - ATTRIBUTES_OFFSET);
407:     }
408: 
409:     private byte attributes() {
410:         // note we're not using the second byte of attributes
411:         return (byte) buffer.getShort(ATTRIBUTES_OFFSET);
412:     }
413: 
414:     @Override
415:     public boolean equals(Object o) {
416:         if (this == o)
417:             return true;
418:         if (o == null || getClass() != o.getClass())
419:             return false;
420: 
421:         DefaultRecordBatch that = (DefaultRecordBatch) o;
422:         return Objects.equals(buffer, that.buffer);
423:     }
424: 
425:     @Override
426:     public int hashCode() {
427:         return buffer != null ? buffer.hashCode() : 0;
428:     }
429: 
430:     private static byte computeAttributes(CompressionType type, TimestampType timestampType,
431:                                           boolean isTransactional, boolean isControl, boolean isDeleteHorizonSet) {
432:         if (timestampType == TimestampType.NO_TIMESTAMP_TYPE)
433:             throw new IllegalArgumentException("Timestamp type must be provided to compute attributes for message " +
434:                     "format v2 and above");
435: 
436:         byte attributes = isTransactional ? TRANSACTIONAL_FLAG_MASK : 0;
437:         if (isControl)
438:             attributes |= CONTROL_FLAG_MASK;
439:         if (type.id > 0)
440:             attributes |= COMPRESSION_CODEC_MASK & type.id;
441:         if (timestampType == TimestampType.LOG_APPEND_TIME)
442:             attributes |= TIMESTAMP_TYPE_MASK;
443:         if (isDeleteHorizonSet)
444:             attributes |= DELETE_HORIZON_FLAG_MASK;
445:         return attributes;
446:     }
447: 
448:     public static void writeEmptyHeader(ByteBuffer buffer,
449:                                         byte magic,
450:                                         long producerId,
451:                                         short producerEpoch,
452:                                         int baseSequence,
453:                                         long baseOffset,
454:                                         long lastOffset,
455:                                         int partitionLeaderEpoch,
456:                                         TimestampType timestampType,
457:                                         long timestamp,
458:                                         boolean isTransactional,
459:                                         boolean isControlRecord) {
460:         int offsetDelta = (int) (lastOffset - baseOffset);
461:         writeHeader(buffer, baseOffset, offsetDelta, DefaultRecordBatch.RECORD_BATCH_OVERHEAD, magic,
462:                     CompressionType.NONE, timestampType, RecordBatch.NO_TIMESTAMP, timestamp, producerId,
463:                     producerEpoch, baseSequence, isTransactional, isControlRecord, false, partitionLeaderEpoch, 0);
464:     }
465: 
466:     public static void writeHeader(ByteBuffer buffer,
467:                                    long baseOffset,
468:                                    int lastOffsetDelta,
469:                                    int sizeInBytes,
470:                                    byte magic,
471:                                    CompressionType compressionType,
472:                                    TimestampType timestampType,
473:                                    long firstTimestamp,
474:                                    long maxTimestamp,
475:                                    long producerId,
476:                                    short epoch,
477:                                    int sequence,
478:                                    boolean isTransactional,
479:                                    boolean isControlBatch,
480:                                    boolean isDeleteHorizonSet,
481:                                    int partitionLeaderEpoch,
482:                                    int numRecords) {
483:         if (magic < RecordBatch.CURRENT_MAGIC_VALUE)
484:             throw new IllegalArgumentException("Invalid magic value " + magic);
485:         if (firstTimestamp < 0 && firstTimestamp != NO_TIMESTAMP)
486:             throw new IllegalArgumentException("Invalid message timestamp " + firstTimestamp);
487: 
488:         short attributes = computeAttributes(compressionType, timestampType, isTransactional, isControlBatch, isDeleteHorizonSet);
489: 
490:         int position = buffer.position();
491:         buffer.putLong(position + BASE_OFFSET_OFFSET, baseOffset);
492:         buffer.putInt(position + LENGTH_OFFSET, sizeInBytes - LOG_OVERHEAD);
493:         buffer.putInt(position + PARTITION_LEADER_EPOCH_OFFSET, partitionLeaderEpoch);
494:         buffer.put(position + MAGIC_OFFSET, magic);
495:         buffer.putShort(position + ATTRIBUTES_OFFSET, attributes);
496:         buffer.putLong(position + BASE_TIMESTAMP_OFFSET, firstTimestamp);
497:         buffer.putLong(position + MAX_TIMESTAMP_OFFSET, maxTimestamp);
498:         buffer.putInt(position + LAST_OFFSET_DELTA_OFFSET, lastOffsetDelta);
499:         buffer.putLong(position + PRODUCER_ID_OFFSET, producerId);
500:         buffer.putShort(position + PRODUCER_EPOCH_OFFSET, epoch);
501:         buffer.putInt(position + BASE_SEQUENCE_OFFSET, sequence);
502:         buffer.putInt(position + RECORDS_COUNT_OFFSET, numRecords);
503:         long crc = Crc32C.compute(buffer, ATTRIBUTES_OFFSET, sizeInBytes - ATTRIBUTES_OFFSET);
504:         buffer.putInt(position + CRC_OFFSET, (int) crc);
505:         buffer.position(position + RECORD_BATCH_OVERHEAD);
506:     }
507: 
508:     @Override
509:     public String toString() {
510:         return "RecordBatch(magic=" + magic() + ", offsets=[" + baseOffset() + ", " + lastOffset() + "], " +
511:                 "sequence=[" + baseSequence() + ", " + lastSequence() + "], " +
512:                 "isTransactional=" + isTransactional() + ", isControlBatch=" + isControlBatch() + ", " +
513:                 "compression=" + compressionType() + ", timestampType=" + timestampType() + ", crc=" + checksum() + ")";
514:     }
