516:     public static int sizeInBytes(long baseOffset, Iterable<Record> records) {
517:         Iterator<Record> iterator = records.iterator();
518:         if (!iterator.hasNext())
519:             return 0;
520: 
521:         int size = RECORD_BATCH_OVERHEAD;
522:         Long firstTimestamp = null;
523:         while (iterator.hasNext()) {
524:             Record record = iterator.next();
525:             int offsetDelta = (int) (record.offset() - baseOffset);
526:             if (firstTimestamp == null)
527:                 firstTimestamp = record.timestamp();
528:             long timestampDelta = record.timestamp() - firstTimestamp;
529:             size += DefaultRecord.sizeInBytes(offsetDelta, timestampDelta, record.key(), record.value(),
530:                     record.headers());
531:         }
532:         return size;
533:     }
534: 
535:     public static int sizeInBytes(Iterable<SimpleRecord> records) {
536:         Iterator<SimpleRecord> iterator = records.iterator();
537:         if (!iterator.hasNext())
538:             return 0;
539: 
540:         int size = RECORD_BATCH_OVERHEAD;
541:         int offsetDelta = 0;
542:         Long firstTimestamp = null;
543:         while (iterator.hasNext()) {
544:             SimpleRecord record = iterator.next();
545:             if (firstTimestamp == null)
546:                 firstTimestamp = record.timestamp();
547:             long timestampDelta = record.timestamp() - firstTimestamp;
548:             size += DefaultRecord.sizeInBytes(offsetDelta++, timestampDelta, record.key(), record.value(),
549:                     record.headers());
550:         }
551:         return size;
552:     }
553: 
554:     /**
555:      * Get an upper bound on the size of a batch with only a single record using a given key and value. This
556:      * is only an estimate because it does not take into account additional overhead from the compression
557:      * algorithm used.
558:      */
559:     static int estimateBatchSizeUpperBound(ByteBuffer key, ByteBuffer value, Header[] headers) {
560:         return RECORD_BATCH_OVERHEAD + DefaultRecord.recordSizeUpperBound(key, value, headers);
561:     }
562: 
563:     public static int incrementSequence(int sequence, int increment) {
564:         if (sequence > Integer.MAX_VALUE - increment)
565:             return increment - (Integer.MAX_VALUE - sequence) - 1;
566:         return sequence + increment;
567:     }
568: 
569:     public static int decrementSequence(int sequence, int decrement) {
570:         if (sequence < decrement)
571:             return Integer.MAX_VALUE - (decrement - sequence) + 1;
572:         return sequence - decrement;
573:     }
