575:     private abstract class RecordIterator implements CloseableIterator<Record> {
576:         private final Long logAppendTime;
577:         private final long baseOffset;
578:         private final long baseTimestamp;
579:         private final int baseSequence;
580:         private final int numRecords;
581:         private int readRecords = 0;
582: 
583:         RecordIterator() {
584:             this.logAppendTime = timestampType() == TimestampType.LOG_APPEND_TIME ? maxTimestamp() : null;
585:             this.baseOffset = baseOffset();
586:             this.baseTimestamp = baseTimestamp();
587:             this.baseSequence = baseSequence();
588:             int numRecords = count();
589:             if (numRecords < 0)
590:                 throw new InvalidRecordException("Found invalid record count " + numRecords + " in magic v" +
591:                         magic() + " batch");
592:             this.numRecords = numRecords;
593:         }
594: 
595:         @Override
596:         public boolean hasNext() {
597:             return readRecords < numRecords;
598:         }
599: 
600:         @Override
601:         public Record next() {
602:             if (readRecords >= numRecords)
603:                 throw new NoSuchElementException();
604: 
605:             readRecords++;
606:             Record rec = readNext(baseOffset, baseTimestamp, baseSequence, logAppendTime);
607:             if (readRecords == numRecords) {
608:                 // Validate that the actual size of the batch is equal to declared size
609:                 // by checking that after reading declared number of items, there no items left
610:                 // (overflow case, i.e. reading past buffer end is checked elsewhere).
611:                 if (!ensureNoneRemaining())
612:                     throw new InvalidRecordException("Incorrect declared batch size, records still remaining in file");
613:             }
614:             return rec;
615:         }
616: 
617:         protected abstract Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime);
618: 
619:         protected abstract boolean ensureNoneRemaining();
620: 
621:         @Override
622:         public void remove() {
623:             throw new UnsupportedOperationException();
624:         }
625: 
626:     }
