628:     private abstract class StreamRecordIterator extends RecordIterator {
629:         private final DataInputStream inputStream;
630: 
631:         StreamRecordIterator(DataInputStream inputStream) {
632:             super();
633:             this.inputStream = inputStream;
634:         }
635: 
636:         abstract Record doReadRecord(long baseOffset, long firstTimestamp, int baseSequence, Long logAppendTime) throws IOException;
637: 
638:         @Override
639:         protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
640:             try {
641:                 return doReadRecord(baseOffset, baseTimestamp, baseSequence, logAppendTime);
642:             } catch (EOFException e) {
643:                 throw new InvalidRecordException("Incorrect declared batch size, premature EOF reached");
644:             } catch (IOException e) {
645:                 throw new KafkaException("Failed to decompress record stream", e);
646:             }
647:         }
648: 
649:         @Override
650:         protected boolean ensureNoneRemaining() {
651:             try {
652:                 return inputStream.read() == -1;
653:             } catch (IOException e) {
654:                 throw new KafkaException("Error checking for remaining bytes after reading batch", e);
655:             }
656:         }
657: 
658:         @Override
659:         public void close() {
660:             try {
661:                 inputStream.close();
662:             } catch (IOException e) {
663:                 throw new KafkaException("Failed to close record stream", e);
664:             }
665:         }
666:     }
