45: /**
46:  * A {@link Records} implementation backed by a ByteBuffer. This is used only for reading or
47:  * modifying in-place an existing buffer of record batches. To create a new buffer see {@link MemoryRecordsBuilder},
48:  * or one of the {@link #builder(ByteBuffer, byte, CompressionType, TimestampType, long)} variants.
49:  */
50: public class MemoryRecords extends AbstractRecords {
51:     private static final Logger log = LoggerFactory.getLogger(MemoryRecords.class);
52:     public static final MemoryRecords EMPTY = MemoryRecords.readableRecords(ByteBuffer.allocate(0));
53: 
54:     private final ByteBuffer buffer;
55: 
56:     private final Iterable<MutableRecordBatch> batches = this::batchIterator;
57: 
58:     private int validBytes = -1;
59: 
60:     // Construct a writable memory records
61:     private MemoryRecords(ByteBuffer buffer) {
62:         Objects.requireNonNull(buffer, "buffer should not be null");
63:         this.buffer = buffer;
64:     }
65: 
66:     @Override
67:     public int sizeInBytes() {
68:         return buffer.limit();
69:     }
70: 
71:     @Override
72:     public long writeTo(TransferableChannel channel, long position, int length) throws IOException {
73:         if (position > Integer.MAX_VALUE)
74:             throw new IllegalArgumentException("position should not be greater than Integer.MAX_VALUE: " + position);
75:         if (position + length > buffer.limit())
76:             throw new IllegalArgumentException("position+length should not be greater than buffer.limit(), position: "
77:                     + position + ", length: " + length + ", buffer.limit(): " + buffer.limit());
78: 
79:         return Utils.tryWriteTo(channel, (int) position, length, buffer);
80:     }
81: 
82:     /**
83:      * Write all records to the given channel (including partial records).
84:      * @param channel The channel to write to
85:      * @return The number of bytes written
86:      * @throws IOException For any IO errors writing to the channel
87:      */
88:     public int writeFullyTo(GatheringByteChannel channel) throws IOException {
89:         buffer.mark();
90:         int written = 0;
91:         while (written < sizeInBytes())
92:             written += channel.write(buffer);
93:         buffer.reset();
94:         return written;
95:     }
96: 
97:     /**
98:      * The total number of bytes in this message set not including any partial, trailing messages. This
99:      * may be smaller than what is returned by {@link #sizeInBytes()}.
100:      * @return The number of valid bytes
101:      */
102:     public int validBytes() {
103:         if (validBytes >= 0)
104:             return validBytes;
105: 
106:         int bytes = 0;
107:         for (RecordBatch batch : batches())
108:             bytes += batch.sizeInBytes();
109: 
110:         this.validBytes = bytes;
111:         return bytes;
112:     }
113: 
114:     @Override
115:     public ConvertedRecords<MemoryRecords> downConvert(byte toMagic, long firstOffset, Time time) {
116:         return RecordsUtil.downConvert(batches(), toMagic, firstOffset, time);
117:     }
118: 
119:     @Override
120:     public AbstractIterator<MutableRecordBatch> batchIterator() {
121:         return new RecordBatchIterator<>(new ByteBufferLogInputStream(buffer.duplicate(), Integer.MAX_VALUE));
122:     }
123: 
124:     /**
125:      * Validates the header of the first batch and returns batch size.
126:      * @return first batch size including LOG_OVERHEAD if buffer contains header up to
127:      *         magic byte, null otherwise
128:      * @throws CorruptRecordException if record size or magic is invalid
129:      */
130:     public Integer firstBatchSize() {
131:         if (buffer.remaining() < HEADER_SIZE_UP_TO_MAGIC)
132:             return null;
133:         return new ByteBufferLogInputStream(buffer, Integer.MAX_VALUE).nextBatchSize();
134:     }
135: 
136:     /**
137:      * Filter the records into the provided ByteBuffer.
138:      *
139:      * @param partition                   The partition that is filtered (used only for logging)
140:      * @param filter                      The filter function
141:      * @param destinationBuffer           The byte buffer to write the filtered records to
142:      * @param maxRecordBatchSize          The maximum record batch size. Note this is not a hard limit: if a batch
143:      *                                    exceeds this after filtering, we log a warning, but the batch will still be
144:      *                                    created.
145:      * @param decompressionBufferSupplier The supplier of ByteBuffer(s) used for decompression if supported. For small
146:      *                                    record batches, allocating a potentially large buffer (64 KB for LZ4) will
147:      *                                    dominate the cost of decompressing and iterating over the records in the
148:      *                                    batch. As such, a supplier that reuses buffers will have a significant
149:      *                                    performance impact.
150:      * @return A FilterResult with a summary of the output (for metrics) and potentially an overflow buffer
151:      */
152:     public FilterResult filterTo(TopicPartition partition, RecordFilter filter, ByteBuffer destinationBuffer,
153:                                  int maxRecordBatchSize, BufferSupplier decompressionBufferSupplier) {
154:         return filterTo(partition, batches(), filter, destinationBuffer, maxRecordBatchSize, decompressionBufferSupplier);
155:     }
156: 
157:     /**
158:      * Note: This method is also used to convert the first timestamp of the batch (which is usually the timestamp of the first record)
159:      * to the delete horizon of the tombstones or txn markers which are present in the batch. 
160:      */
161:     private static FilterResult filterTo(TopicPartition partition, Iterable<MutableRecordBatch> batches,
162:                                          RecordFilter filter, ByteBuffer destinationBuffer, int maxRecordBatchSize,
163:                                          BufferSupplier decompressionBufferSupplier) {
164:         FilterResult filterResult = new FilterResult(destinationBuffer);
165:         ByteBufferOutputStream bufferOutputStream = new ByteBufferOutputStream(destinationBuffer);
166:         for (MutableRecordBatch batch : batches) {
167:             final BatchRetentionResult batchRetentionResult = filter.checkBatchRetention(batch);
168:             final boolean containsMarkerForEmptyTxn = batchRetentionResult.containsMarkerForEmptyTxn;
169:             final BatchRetention batchRetention = batchRetentionResult.batchRetention;
170: 
171:             filterResult.bytesRead += batch.sizeInBytes();
172: 
173:             if (batchRetention == BatchRetention.DELETE)
174:                 continue;
175: 
176:             // We use the absolute offset to decide whether to retain the message or not. Due to KAFKA-4298, we have to
177:             // allow for the possibility that a previous version corrupted the log by writing a compressed record batch
178:             // with a magic value not matching the magic of the records (magic < 2). This will be fixed as we
179:             // recopy the messages to the destination buffer.
180:             byte batchMagic = batch.magic();
181:             List<Record> retainedRecords = new ArrayList<>();
182: 
183:             final BatchFilterResult iterationResult = filterBatch(batch, decompressionBufferSupplier, filterResult, filter,
184:                     batchMagic, true, retainedRecords);
185:             boolean containsTombstones = iterationResult.containsTombstones;
186:             boolean writeOriginalBatch = iterationResult.writeOriginalBatch;
187:             long maxOffset = iterationResult.maxOffset;
188: 
189:             if (!retainedRecords.isEmpty()) {
190:                 // we check if the delete horizon should be set to a new value
191:                 // in which case, we need to reset the base timestamp and overwrite the timestamp deltas
192:                 // if the batch does not contain tombstones, then we don't need to overwrite batch
193:                 boolean needToSetDeleteHorizon = batch.magic() >= RecordBatch.MAGIC_VALUE_V2 && (containsTombstones || containsMarkerForEmptyTxn)
194:                     && !batch.deleteHorizonMs().isPresent();
195:                 if (writeOriginalBatch && !needToSetDeleteHorizon) {
196:                     batch.writeTo(bufferOutputStream);
197:                     filterResult.updateRetainedBatchMetadata(batch, retainedRecords.size(), false);
198:                 } else {
199:                     final MemoryRecordsBuilder builder;
200:                     long deleteHorizonMs;
201:                     if (needToSetDeleteHorizon)
202:                         deleteHorizonMs = filter.currentTime + filter.deleteRetentionMs;
203:                     else
204:                         deleteHorizonMs = batch.deleteHorizonMs().orElse(RecordBatch.NO_TIMESTAMP);
205:                     builder = buildRetainedRecordsInto(batch, retainedRecords, bufferOutputStream, deleteHorizonMs);
206: 
207:                     MemoryRecords records = builder.build();
208:                     int filteredBatchSize = records.sizeInBytes();
209:                     if (filteredBatchSize > batch.sizeInBytes() && filteredBatchSize > maxRecordBatchSize)
210:                         log.warn("Record batch from {} with last offset {} exceeded max record batch size {} after cleaning " +
211:                                         "(new size is {}). Consumers with version earlier than 0.10.1.0 may need to " +
212:                                         "increase their fetch sizes.",
213:                                 partition, batch.lastOffset(), maxRecordBatchSize, filteredBatchSize);
214: 
215:                     MemoryRecordsBuilder.RecordsInfo info = builder.info();
216:                     filterResult.updateRetainedBatchMetadata(info.maxTimestamp, info.shallowOffsetOfMaxTimestamp,
217:                             maxOffset, retainedRecords.size(), filteredBatchSize);
218:                 }
219:             } else if (batchRetention == BatchRetention.RETAIN_EMPTY) {
220:                 if (batchMagic < RecordBatch.MAGIC_VALUE_V2)
221:                     throw new IllegalStateException("Empty batches are only supported for magic v2 and above");
222: 
223:                 bufferOutputStream.ensureRemaining(DefaultRecordBatch.RECORD_BATCH_OVERHEAD);
224:                 DefaultRecordBatch.writeEmptyHeader(bufferOutputStream.buffer(), batchMagic, batch.producerId(),
225:                         batch.producerEpoch(), batch.baseSequence(), batch.baseOffset(), batch.lastOffset(),
226:                         batch.partitionLeaderEpoch(), batch.timestampType(), batch.maxTimestamp(),
227:                         batch.isTransactional(), batch.isControlBatch());
228:                 filterResult.updateRetainedBatchMetadata(batch, 0, true);
229:             }
230: 
231:             // If we had to allocate a new buffer to fit the filtered buffer (see KAFKA-5316), return early to
232:             // avoid the need for additional allocations.
233:             ByteBuffer outputBuffer = bufferOutputStream.buffer();
234:             if (outputBuffer != destinationBuffer) {
235:                 filterResult.outputBuffer = outputBuffer;
236:                 return filterResult;
237:             }
238:         }
239: 
240:         return filterResult;
241:     }
242: 
243:     private static BatchFilterResult filterBatch(RecordBatch batch,
244:                                                  BufferSupplier decompressionBufferSupplier,
245:                                                  FilterResult filterResult,
246:                                                  RecordFilter filter,
247:                                                  byte batchMagic,
248:                                                  boolean writeOriginalBatch,
249:                                                  List<Record> retainedRecords) {
250:         long maxOffset = -1;
251:         boolean containsTombstones = false;
252:         try (final CloseableIterator<Record> iterator = batch.streamingIterator(decompressionBufferSupplier)) {
253:             while (iterator.hasNext()) {
254:                 Record record = iterator.next();
255:                 filterResult.messagesRead += 1;
256: 
257:                 if (filter.shouldRetainRecord(batch, record)) {
258:                     // Check for log corruption due to KAFKA-4298. If we find it, make sure that we overwrite
259:                     // the corrupted batch with correct data.
260:                     if (!record.hasMagic(batchMagic))
261:                         writeOriginalBatch = false;
262: 
263:                     if (record.offset() > maxOffset)
264:                         maxOffset = record.offset();
265: 
266:                     retainedRecords.add(record);
267: 
268:                     if (!record.hasValue()) {
269:                         containsTombstones = true;
270:                     }
271:                 } else {
272:                     writeOriginalBatch = false;
273:                 }
274:             }
275:             return new BatchFilterResult(writeOriginalBatch, containsTombstones, maxOffset);
276:         }
277:     }
