279:     private static class BatchFilterResult {
280:         private final boolean writeOriginalBatch;
281:         private final boolean containsTombstones;
282:         private final long maxOffset;
283:         private BatchFilterResult(final boolean writeOriginalBatch,
284:                                  final boolean containsTombstones,
285:                                  final long maxOffset) {
286:             this.writeOriginalBatch = writeOriginalBatch;
287:             this.containsTombstones = containsTombstones;
288:             this.maxOffset = maxOffset;
289:         }
290:     }
