292:     private static MemoryRecordsBuilder buildRetainedRecordsInto(RecordBatch originalBatch,
293:                                                                  List<Record> retainedRecords,
294:                                                                  ByteBufferOutputStream bufferOutputStream,
295:                                                                  final long deleteHorizonMs) {
296:         byte magic = originalBatch.magic();
297:         TimestampType timestampType = originalBatch.timestampType();
298:         long logAppendTime = timestampType == TimestampType.LOG_APPEND_TIME ?
299:                 originalBatch.maxTimestamp() : RecordBatch.NO_TIMESTAMP;
300:         long baseOffset = magic >= RecordBatch.MAGIC_VALUE_V2 ?
301:                 originalBatch.baseOffset() : retainedRecords.get(0).offset();
302: 
303:         MemoryRecordsBuilder builder = new MemoryRecordsBuilder(bufferOutputStream, magic,
304:                 originalBatch.compressionType(), timestampType, baseOffset, logAppendTime, originalBatch.producerId(),
305:                 originalBatch.producerEpoch(), originalBatch.baseSequence(), originalBatch.isTransactional(),
306:                 originalBatch.isControlBatch(), originalBatch.partitionLeaderEpoch(), bufferOutputStream.limit(), deleteHorizonMs);
307: 
308:         for (Record record : retainedRecords)
309:             builder.append(record);
310: 
311:         if (magic >= RecordBatch.MAGIC_VALUE_V2)
312:             // we must preserve the last offset from the initial batch in order to ensure that the
313:             // last sequence number from the batch remains even after compaction. Otherwise, the producer
314:             // could incorrectly see an out of sequence error.
315:             builder.overrideLastOffset(originalBatch.lastOffset());
316: 
317:         return builder;
318:     }
