395:     public static class FilterResult {
396:         private ByteBuffer outputBuffer;
397:         private int messagesRead = 0;
398:         // Note that `bytesRead` should contain only bytes from batches that have been processed, i.e. bytes from
399:         // `messagesRead` and any discarded batches.
400:         private int bytesRead = 0;
