417:         private void updateRetainedBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset,
418:                                                 int messagesRetained, int bytesRetained) {
419:             validateBatchMetadata(maxTimestamp, shallowOffsetOfMaxTimestamp, maxOffset);
420:             if (maxTimestamp > this.maxTimestamp) {
