430:             if (maxTimestamp != RecordBatch.NO_TIMESTAMP && shallowOffsetOfMaxTimestamp < 0)
431:                 throw new IllegalArgumentException("shallowOffset undefined for maximum timestamp " + maxTimestamp);
432:             if (maxOffset < 0)
433:                 throw new IllegalArgumentException("maxOffset undefined");
434:         }
